import { useState } from 'react'

export default function ManageHabitsScreen({ habits, onAdd, onDelete, onNavigate }) {
  const [input, setInput] = useState('')

  function handleAdd() {
    if (!input.trim()) return
    onAdd(input)
    setInput('')
  }

  return (
    <div className="screen">
      <header>
        <button className="link-btn" onClick={onNavigate}>← Back</button>
        <h1>Manage Habits</h1>
      </header>

      <div className="add-row">
        <input
          type="text"
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && handleAdd()}
          placeholder="New habit name"
        />
        <button className="primary-btn" onClick={handleAdd} disabled={!input.trim()}>
          Add
        </button>
      </div>

      {habits.length === 0 ? (
        <p className="empty">No habits yet. Add one above.</p>
      ) : (
        <ul className="habit-list">
          {habits.map(habit => (
            <li key={habit.id} className="habit-item">
              <span className="name">{habit.name}</span>
              <button className="delete-btn" onClick={() => onDelete(habit.id)}>
                Delete
              </button>
            </li>
          ))}
        </ul>
      )}
    </div>
  )
}import { calculateStreak, getToday } from '../utils/streaks'

export default function TodayScreen({ habits, completions, onToggle, onNavigate }) {
  const today = getToday()
  const formattedDate = new Date().toLocaleDateString('en-US', {
    weekday: 'long',
    month: 'long',
    day: 'numeric',
  })

  return (
    <div className="screen">
      <header>
        <h1>Today</h1>
        <button className="link-btn" onClick={onNavigate}>Manage</button>
      </header>

      <p className="date">{formattedDate}</p>

      {habits.length === 0 ? (
        <p className="empty">No habits yet. Tap Manage to add some.</p>
      ) : (
        <ul className="habit-list">
          {habits.map(habit => {
            const dates = completions[habit.id] || []
            const done = dates.includes(today)
            const streak = calculateStreak(dates)
            return (
              <li key={habit.id} className={`habit-item${done ? ' done' : ''}`}>
                <label>
                  <input
                    type="checkbox"
                    checked={done}
                    onChange={() => onToggle(habit.id)}
                  />
                  <span className="name">{habit.name}</span>
                </label>
                {streak > 0 && <span className="streak">🔥 {streak}</span>}
              </li>
            )
          })}
        </ul>
      )}
    </div>
  )
}const STORAGE_KEY = 'habit-tracker-data';

export function loadData() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return { habits: [], completions: {} };
    return JSON.parse(raw);
  } catch {
    return { habits: [], completions: {} };
  }
}

export function saveData(data) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
}export function getToday() {
  return new Date().toISOString().slice(0, 10);
}

export function calculateStreak(dates) {
  if (!dates || dates.length === 0) return 0;

  const dateSet = new Set(dates);
  const today = getToday();
  const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0, 10);

  // Start from today if completed, otherwise yesterday
  let checkDate = dateSet.has(today) ? today : yesterday;
  if (!dateSet.has(checkDate)) return 0;

  let streak = 0;
  let current = new Date(checkDate + 'T12:00:00');

  while (dateSet.has(current.toISOString().slice(0, 10))) {
    streak++;
    current.setDate(current.getDate() - 1);
  }

  return streak;
}

