  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background: #f0f2f5;
  color: #1a1a1a;
}

.screen {
  max-width: 480px;
  margin: 0 auto;
  padding: 16px;
  min-height: 100vh;
  background: #fff;
}

header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 0;
  border-bottom: 1px solid #eee;
  margin-bottom: 12px;
}

h1 {
  font-size: 20px;
  font-weight: 600;
}

.date {
  color: #666;
  font-size: 14px;
  margin-bottom: 16px;
}

.empty {
  color: #aaa;
  text-align: center;
  margin-top: 48px;
  font-size: 15px;
}

/* Habit list */
.habit-list {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.habit-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: #fafafa;
  border: 1px solid #e8e8e8;
  border-radius: 10px;
  padding: 14px 16px;
}

.habit-item.done {
  background: #f0faf0;
  border-color: #c8e6c9;
}

.habit-item label {
  display: flex;
  align-items: center;
  gap: 12px;
  cursor: pointer;
  flex: 1;
}

.habit-item input[type='checkbox'] {
  width: 18px;
  height: 18px;
  cursor: pointer;
  accent-color: #4caf50;
}

.habit-item .name {
  font-size: 16px;
}

.habit-item.done .name {
  text-decoration: line-through;
  color: #aaa;
}

.streak {
  font-size: 14px;
  font-weight: 500;
  white-space: nowrap;
}

/* Add row */
.add-row {
  display: flex;
  gap: 8px;
  margin: 16px 0;
}

.add-row input {
  flex: 1;
  padding: 10px 14px;
  border: 1px solid #ddd;
  border-radius: 8px;
  font-size: 15px;
  outline: none;
  transition: border-color 0.15s;
}

.add-row input:focus {
  border-color: #4a90e2;
}

/* Buttons */
button {
  border: none;
  border-radius: 8px;
  cursor: pointer;
  font-size: 14px;
  font-weight: 500;
  transition: opacity 0.15s;
}

button:disabled {
  opacity: 0.35;
  cursor: default;
}

.link-btn {
  background: transparent;
  color: #4a90e2;
  padding: 8px 4px;
}

.primary-btn {
  background: #4a90e2;
  color: #fff;
  padding: 10px 18px;
}

.delete-btn {
  background: transparent;
  color: #e53935;
  padding: 6px 10px;
}

